import microcoapy
import network
import machine

# Connect to WiFi
def connect_wifi(ssid, password):
    wlan = network.WLAN(network.STA_IF)
    wlan.active(True)
    wlan.connect(ssid, password)
    while not wlan.isconnected():
        pass
    print('Connected to WiFi:', wlan.ifconfig())

# CoAP server setup
def start_coap_server():
    server = microcoapy.Coap()
    server.start()

    # Resource: /sensors/temp
    def handle_temp_request(packet, sender):
        if packet.code == microcoapy.COAP_METHOD_GET:
            temp = read_temperature_sensor()
            response = server.build_response(packet, payload=str(temp))
            server.send_response(sender, response)

    # Resource: /actuators/light
    def handle_light_request(packet, sender):
        if packet.code == microcoapy.COAP_METHOD_GET:
            light_status = read_light_status()
            response = server.build_response(packet, payload=str(light_status))
            server.send_response(sender, response)
        elif packet.code == microcoapy.COAP_METHOD_PUT:
            new_status = packet.payload.decode('utf-8')
            set_light_status(new_status)
            response = server.build_response(packet, payload='OK')
            server.send_response(sender, response)

    server.add_resource('/sensors/temp', handle_temp_request)
    server.add_resource('/actuators/light', handle_light_request)

    print('CoAP server started')
    try:
        while True:
            server.poll(1000)
    except KeyboardInterrupt:
        print('Stopping CoAP server')
    finally:
        server.stop()

# Mock sensor and actuator functions
def read_temperature_sensor():
    return 25  # Mock temperature value

def read_light_status():
    return 'OFF'  # Mock light status

def set_light_status(status):
    print(f'Light status set to: {status}')

